import random
from math import gcd

def generate_dh_parameters():
    # Large prime p and generator g
    p = 23  # Small example prime
    g = 5   # Generator
    return p, g

def generate_private_key(p):
    # Random private key (1 < a < p-1)
    return random.randrange(2, p-1)

def compute_public_key(g, private_key, p):
    # Public key = g^private mod p
    return pow(g, private_key, p)

def compute_shared_secret(public_key_b, private_key_a, p):
    # Shared secret = (Public_B)^Private_A mod p
    return pow(public_key_b, private_key_a, p)

# Example execution:
# p, g = generate_dh_parameters()
# Alice: a = generate_private_key(p); A = compute_public_key(g, a, p)
# Bob: b = generate_private_key(p); B = compute_public_key(g, b, p)
# Shared secret: Alice computes B^a mod p, Bob computes A^b mod p
